package sn.gestionimmobiliere.backend.identity.domain;
import java.time.Instant;import java.util.UUID;import jakarta.persistence.*;
@Entity @Table(name="app_users")public class AppUser{@Id private UUID id;@Column(name="organization_id")private UUID organizationId;private String email;@Column(name="password_hash")private String passwordHash;@Column(name="full_name")private String fullName;@Enumerated(EnumType.STRING)private UserRole role;private String status;@Column(name="created_at")private Instant createdAt;@Column(name="updated_at")private Instant updatedAt;protected AppUser(){}public AppUser(UUID id,UUID org,String email,String hash,String name,UserRole role,Instant now){this.id=id;organizationId=org;this.email=email;passwordHash=hash;fullName=name;this.role=role;status="ACTIVE";createdAt=now;updatedAt=now;}public UUID getId(){return id;}public UUID getOrganizationId(){return organizationId;}public String getEmail(){return email;}public String getPasswordHash(){return passwordHash;}public String getFullName(){return fullName;}public UserRole getRole(){return role;}public String getStatus(){return status;}}
